import React from 'react';

const gold = '#D4AF37';
const terracotta = '#C04000';

const Menu = () => {
  const chops = [
    { name: "Classic Mosa & Samosa", price: "3,000", qty: "10 pcs" },
    { name: "Puff Puff & Springrolls", price: "2,500", qty: "12 pcs" },
    { name: "The Platter Mix", price: "8,000", qty: "Large" }
  ];

  return (
    <div style={{ padding: '0 15px', marginTop: '-20px' }}>
      <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '10px' }}>
        The Curation
      </h3>
      
      {chops.map((item) => (
        <div key={item.name} style={{ 
          display: 'flex', 
          backgroundColor: '#111', 
          borderRadius: '8px', 
          marginBottom: '8px', 
          padding: '10px', 
          alignItems: 'center',
          borderLeft: `3px solid ${gold}` // Gold touch for Small Chops
        }}>
          <div style={{ width: '50px', height: '50px', backgroundColor: '#000', borderRadius: '4px', marginRight: '12px' }}></div>
          <div style={{ flex: 1 }}>
            <h4 style={{ fontSize: '0.8rem', margin: '0', color: '#fff' }}>{item.name}</h4>
            <p style={{ fontSize: '0.6rem', color: '#666', margin: '2px 0' }}>{item.qty}</p>
            <div style={{ fontSize: '0.85rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
          </div>
          <button style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '4px', padding: '5px 10px', fontSize: '0.6rem', fontWeight: 'bold' }}>ADD</button>
        </div>
      ))}
    </div>
  );
};

export default Menu;
